CREATE OR REPLACE FUNCTION public.cleanup_old_audit_log_entries()
 RETURNS TABLE(deleted_count integer, space_before text, space_after text)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_deleted_count INTEGER;
    v_size_before BIGINT;
    v_size_after BIGINT;
BEGIN
    SELECT pg_total_relation_size('audit_log_entries') INTO v_size_before;

    DELETE FROM audit_log_entries
    WHERE timestamp < NOW() - INTERVAL '90 days';

    GET DIAGNOSTICS v_deleted_count = ROW_COUNT;

    SELECT pg_total_relation_size('audit_log_entries') INTO v_size_after;

    RETURN QUERY SELECT
        v_deleted_count,
        pg_size_pretty(v_size_before),
        pg_size_pretty(v_size_after);
END;
$function$

